/**
 * @name Code injection via eval in ImageMath
 * @description Using eval with user-controlled input can lead to arbitrary code execution
 * @kind path-problem
 * @problem.severity error
 * @id py/imagemath-code-injection
 * @tags security
 *        external/cwe/cwe-094
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.ApiGraphs

module CodeInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Any parameter to a public function
    source instanceof DataFlow::ParameterNode
    or
    // Remote flow sources
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Argument to eval() or exec()
    exists(DataFlow::CallCfgNode call |
      call = API::builtin("eval").getACall() or
      call = API::builtin("exec").getACall() |
      sink = call.getArg(_)
    )
  }
}

module CodeInjectionFlow = TaintTracking::Global<CodeInjectionConfig>;
import CodeInjectionFlow::PathGraph

from CodeInjectionFlow::PathNode source, CodeInjectionFlow::PathNode sink
where CodeInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Code injection from $@.", source.getNode(), "user-controlled input"

/**
 * @name Command injection in EPS image processing
 * @description User-controlled file paths may flow to command execution in EPS plugin
 * @kind path-problem
 * @problem.severity error
 * @id py/eps-command-injection-flow
 * @tags security
 *        external/cwe/cwe-078
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.Concepts
import semmle.python.ApiGraphs

module EpsCommandInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // File paths from Image.open or similar
    exists(DataFlow::CallCfgNode call |
      call = API::moduleImport("PIL").getMember("Image").getMember("open").getACall() and
      source = call.getArg(0)
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(SystemCommandExecution cmd |
      sink = cmd.getCommand() and
      cmd.getLocation().getFile().getBaseName() = "EpsImagePlugin.py"
    )
  }
}

module EpsCommandInjectionFlow = TaintTracking::Global<EpsCommandInjectionConfig>;
import EpsCommandInjectionFlow::PathGraph

from EpsCommandInjectionFlow::PathNode source, EpsCommandInjectionFlow::PathNode sink
where EpsCommandInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Command injection from $@.", source.getNode(), "file path"
